/**
 * @fileoverview Checkbox barrel.
 * @module module/Checkbox
 */
import { default as razyui } from '../index.js';
import { CheckboxDef as DEF } from './Checkbox.def.js';
import Checkbox from './Checkbox/index.js';

razyui.Checkbox = Checkbox;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Checkbox);
}

export default Checkbox;

export const stylesheet = null;
