/**
 * @fileoverview Checkbox component definition for JIT pipeline.
 * @module module/Checkbox.def
 */

import { PART } from './Checkbox/constants.js';

export const CheckboxDef = {
    name: 'Checkbox',
    tag: 'rui-checkbox',

    tokens: {
        prefix: 'cb',
        tokens: {
            'font-size':      { ref: 'font.size-sm',       description: 'Label font size' },
            'font-stack':     { ref: 'font.family',        description: 'Font family' },
            'size':           { value: '1.125rem',         description: 'Box size' },
            'gap':            { ref: 'spacing.2',           description: 'Box-to-label gap' },
            'bg':             { ref: 'color.bg',            description: 'Box background' },
            'border':         { ref: 'color.border',        description: 'Box border' },
            'radius':         { value: '0.25rem',           description: 'Box radius' },
            'text':           { ref: 'color.text',          description: 'Label text' },
            'checked-bg':     { ref: 'color.accent',        description: 'Checked background' },
            'checked-border': { ref: 'color.accent',        description: 'Checked border' },
            'check-color':    { value: '#fff',              description: 'Check mark color' },
            'hover-border':   { ref: 'color.accent',        description: 'Hover border' },

            'sm-size':        { value: '0.875rem',          description: 'Small box size' },
            'sm-font-size':   { value: '0.75rem',           description: 'Small font size' },
            'lg-size':        { value: '1.375rem',          description: 'Large box size' },
            'lg-font-size':   { ref: 'font.size-base',     description: 'Large font size' },
        },
    },

    states: {
        initial: 'unchecked',
        states: {
            unchecked:     { on: { CHECK: 'checked', INDETERMINATE: 'indeterminate', DISABLE: 'disabled' } },
            checked:       { on: { UNCHECK: 'unchecked', INDETERMINATE: 'indeterminate', DISABLE: 'disabled' } },
            indeterminate: { on: { CHECK: 'checked', UNCHECK: 'unchecked', DISABLE: 'disabled' } },
            disabled:      { on: { ENABLE: 'unchecked', ENABLE_CHECKED: 'checked' } },
        },
    },

    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.BOX]: PART.BOX,
        [PART.CHECK]: PART.CHECK,
        [PART.LABEL]: PART.LABEL,
        [PART.SM_ROOT]: PART.SM_ROOT,
        [PART.LG_ROOT]: PART.LG_ROOT,
    },

    observedAttrs: ['checked', 'disabled', 'indeterminate', 'value', 'name', 'size'],
};
